package com.bank.accounts.service.impl;

import com.bank.accounts.constants.AccountsConstants;
import com.bank.accounts.dto.AccountsDto;
import com.bank.accounts.dto.CustomerDto;
import com.bank.accounts.entity.Accounts;
import com.bank.accounts.entity.Customer;
import com.bank.accounts.exception.CustomerAlreadyExistsException;
import com.bank.accounts.mapper.AccountsMapper;
import com.bank.accounts.mapper.CustomerMapper;
import com.bank.accounts.repository.AccountsRepository;
import com.bank.accounts.repository.CustomerRepository;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.MockedStatic;
import org.mockito.Mockito;
import org.mockito.junit.jupiter.MockitoExtension;

import java.util.Optional;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.*;

@ExtendWith(MockitoExtension.class)
class AccountServiceTest {

    @Mock
    private AccountsRepository accountsRepository;

    @Mock
    private CustomerRepository customerRepository;

    @InjectMocks
    private AccountService accountService;

    private CustomerDto customerDto;
    private Customer customer;
    private Accounts accounts;

    @BeforeEach
    void setUp() {
        customerDto = new CustomerDto();
        customerDto.setName("Test Name");
        customerDto.setEmail("test@example.com");
        customerDto.setMobileNumber("1234567890");

        customer = new Customer();
        customer.setCustomerId(1L);
        customer.setName("Test Name");
        customer.setEmail("test@example.com");
        customer.setMobileNumber("1234567890");

        accounts = new Accounts();
        accounts.setCustomerId(1L);
        accounts.setAccountNumber(1234567890L);
        accounts.setAccountType(AccountsConstants.SAVINGS);
        accounts.setBranchAddress(AccountsConstants.ADDRESS);
    }

    @Test
    @DisplayName("Should create a new account successfully")
    void createAccount_Success() {
        when(customerRepository.findByMobileNumber(customerDto.getMobileNumber())).thenReturn(Optional.empty());
        when(customerRepository.save(any(Customer.class))).thenReturn(customer);
        when(accountsRepository.save(any(Accounts.class))).thenReturn(accounts);

        try (MockedStatic<CustomerMapper> customerMapperMock = Mockito.mockStatic(CustomerMapper.class)) {
            customerMapperMock.when(() -> CustomerMapper.mapToCustomer(any(CustomerDto.class), any(Customer.class)))
                    .thenReturn(customer);

            accountService.createAccount(customerDto);

            verify(customerRepository, times(1)).findByMobileNumber(customerDto.getMobileNumber());
            verify(customerRepository, times(1)).save(any(Customer.class));
            verify(accountsRepository, times(1)).save(any(Accounts.class));
        }
    }

    @Test
    @DisplayName("Should throw CustomerAlreadyExistsException when customer already exists")
    void createAccount_CustomerAlreadyExists() {
        when(customerRepository.findByMobileNumber(customerDto.getMobileNumber())).thenReturn(Optional.of(customer));

        assertThrows(CustomerAlreadyExistsException.class, () -> accountService.createAccount(customerDto));

        verify(customerRepository, times(1)).findByMobileNumber(customerDto.getMobileNumber());
        verify(customerRepository, never()).save(any(Customer.class));
        verify(accountsRepository, never()).save(any(Accounts.class));
    }

    @Test
    @DisplayName("Should handle null CustomerDto gracefully")
    void createAccount_NullCustomerDto() {
        assertThrows(IllegalArgumentException.class, () -> accountService.createAccount(null));
        verify(customerRepository, never()).findByMobileNumber(anyString());
        verify(customerRepository, never()).save(any(Customer.class));
        verify(accountsRepository, never()).save(any(Accounts.class));
    }
}

package com.bank.accounts.service.impl;

