import com.bank.accounts.repository.CustomerRepository;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.MockedStatic;
import org.mockito.Mockito;
import org.mockito.junit.jupiter.MockitoExtension;

import java.util.Optional;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.*;

@ExtendWith(MockitoExtension.class)
class AccountServiceTest {

    @Mock
    private AccountsRepository accountsRepository;

    @Mock
    private CustomerRepository customerRepository;

    @InjectMocks
    private AccountService accountService;

    private CustomerDto customerDto;
    private Customer customer;
    private Accounts accounts;

    @BeforeEach
    void setUp() {
        customerDto = new CustomerDto();
        customerDto.setName("Test Name");
        customerDto.setEmail("test@example.com");
        customerDto.setMobileNumber("1234567890");

        customer = new Customer();
        customer.setCustomerId(1L);
        customer.setName("Test Name");
        customer.setEmail("test@example.com");
        customer.setMobileNumber("1234567890");

        accounts = new Accounts();
        accounts.setCustomerId(1L);
        accounts.setAccountNumber(1234567890L);
        accounts.setAccountType(AccountsConstants.SAVINGS);
        accounts.setBranchAddress(AccountsConstants.ADDRESS);
    }

    @Test
    @DisplayName("Should fetch account details successfully")
    void getAccount_Success() {
        when(customerRepository.findByMobileNumber(anyString())).thenReturn(Optional.of(customer));
        when(accountsRepository.findByCustomerId(anyLong())).thenReturn(Optional.of(accounts));

        try (MockedStatic<CustomerMapper> customerMapperMock = Mockito.mockStatic(CustomerMapper.class);
             MockedStatic<AccountsMapper> accountsMapperMock = Mockito.mockStatic(AccountsMapper.class)) {

            customerMapperMock.when(() -> CustomerMapper.mapToCustomerDto(any(Customer.class), any(CustomerDto.class)))
                    .thenReturn(customerDto);
            accountsMapperMock.when(() -> AccountsMapper.mapToAccountsDto(any(Accounts.class), any(AccountsDto.class)))
                    .thenReturn(new AccountsDto());

            CustomerDto result = accountService.getAccount("1234567890");

            assertNotNull(result);
            assertEquals("Test Name", result.getName());
            verify(customerRepository, times(1)).findByMobileNumber(anyString());
            verify(accountsRepository, times(1)).findByCustomerId(anyLong());
        }
    }

    @Test
    @DisplayName("Should throw ResourceNotFoundException when customer not found")
    void getAccount_CustomerNotFound() {
        when(customerRepository.findByMobileNumber(anyString())).thenReturn(Optional.empty());

        assertThrows(ResourceNotFoundException.class, () -> accountService.getAccount("1234567890"));

        verify(customerRepository, times(1)).findByMobileNumber(anyString());
        verify(accountsRepository, never()).findByCustomerId(anyLong());
    }

    @Test
    @DisplayName("Should throw ResourceNotFoundException when account not found for customer")
    void getAccount_AccountNotFound() {
        when(customerRepository.findByMobileNumber(anyString())).thenReturn(Optional.of(customer));
        when(accountsRepository.findByCustomerId(anyLong())).thenReturn(Optional.empty());

        assertThrows(ResourceNotFoundException.class, () -> accountService.getAccount("1234567890"));

        verify(customerRepository, times(1)).findByMobileNumber(anyString());
        verify(accountsRepository, times(1)).findByCustomerId(anyLong());
    }
}

package com.bank.accounts.controller;

import com.bank.accounts.constants.AccountsConstants;
import com.bank.accounts.dto.CustomerDto;
import com.bank.accounts.dto.ResponseDto;
import com.bank.accounts.service.IAccountService;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.*;

@ExtendWith(MockitoExtension.class)
class AccountsControllerTest {

    @Mock
    private IAccountService accountService;

    @InjectMocks
    private AccountsController accountsController;

    private CustomerDto customerDto;

    @BeforeEach
    void setUp() {
        customerDto = new CustomerDto();
        customerDto.setName("Test Name");
        customerDto.setEmail("test@example.com");
        customerDto.setMobileNumber("1234567890");
    }

    @Test
    @DisplayName("Should create account successfully and return 201 CREATED")
    void createAccount_Success() {
        doNothing().when(accountService).createAccount(any(CustomerDto.class));

        ResponseEntity<ResponseDto> response = accountsController.createAccount(customerDto);

        assertNotNull(response);
        assertEquals(HttpStatus.CREATED, response.getStatusCode());
        assertEquals(AccountsConstants.STATUS_201, response.getBody().getStatusCode());
        assertEquals(AccountsConstants.MESSAGE_201, response.getBody().getStatusMsg());
        verify(accountService, times(1)).createAccount(any(CustomerDto.class));
    }

    @Test
    @DisplayName("Should handle service exception during account creation")
    void createAccount_ServiceException() {
        doThrow(new RuntimeException("Service error")).when(accountService).createAccount(any(CustomerDto.class));

        // The GlobalExceptionHandler will catch this, so we test that the service method was called.
        // For a full integration test, we'd use MockMvc to verify the error response.
        try {
            accountsController.createAccount(customerDto);
        } catch (RuntimeException e) {
            assertEquals("Service error", e.getMessage());
        }

        verify(accountService, times(1)).createAccount(any(CustomerDto.class));
    }
}

